package com.rabitah.frontend;
import com.rabitah.frontend.api.*; import com.rabitah.frontend.navigation.SceneRouter; import com.rabitah.frontend.session.SessionManager; import java.net.URI; import java.util.concurrent.*;
public final class AppContext implements AutoCloseable {private final ExecutorService executor=Executors.newVirtualThreadPerTaskExecutor();private final URI apiBase=resolveApiBase();private final SessionManager session=new SessionManager();private final ApiClient api=new ApiClient(apiBase,session,executor);private final AuthApiService auth=new AuthApiService(api);private final ApprovalSocket approvals=new ApprovalSocket(apiBase,executor);private final SceneRouter router=new SceneRouter(this);private static URI resolveApiBase(){String configured=System.getProperty("rabitah.api");if(configured==null||configured.isBlank())configured=System.getenv("RABITAH_API_BASE_URL");if(configured!=null&&!configured.isBlank()){if(!configured.endsWith("/"))configured+="/";return URI.create(configured);}return ServerDiscovery.discover(java.time.Duration.ofSeconds(3)).orElse(URI.create("http://127.0.0.1:8080/api/v1/"));}public SessionManager session(){return session;}public AuthApiService auth(){return auth;}public ApiClient api(){return api;}public ApprovalSocket approvals(){return approvals;}public URI apiBase(){return apiBase;}public SceneRouter router(){return router;}public Executor executor(){return executor;}@Override public void close(){session.clear();approvals.close();executor.shutdownNow();}}
